/**
 * @summary Send a message to the farming AI chatbot
 */
export const getSendChatMessageUrl = () => {
  return `/api/chat`;
};

export const sendChatMessage = async (
  chatMessageBody: ChatMessageBody,
  options?: RequestInit,
): Promise<ChatResponse> => {
  return customFetch<ChatResponse>(getSendChatMessageUrl(), {
    ...options,
    method: "POST",
    headers: { "Content-Type": "application/json", ...options?.headers },
    body: JSON.stringify(chatMessageBody),
  });
};

export const getSendChatMessageMutationOptions = <
  TError = ErrorType<unknown>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof sendChatMessage>>,
    TError,
    { data: BodyType<ChatMessageBody> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationOptions<
  Awaited<ReturnType<typeof sendChatMessage>>,
  TError,
  { data: BodyType<ChatMessageBody> },
  TContext
> => {
  const mutationKey = ["sendChatMessage"];
  const { mutation: mutationOptions, request: requestOptions } = options
    ? options.mutation &&
      "mutationKey" in options.mutation &&
      options.mutation.mutationKey
      ? options
      : { ...options, mutation: { ...options.mutation, mutationKey } }
    : { mutation: { mutationKey }, request: undefined };

  const mutationFn: MutationFunction<
    Awaited<ReturnType<typeof sendChatMessage>>,
    { data: BodyType<ChatMessageBody> }
  > = (props) => {
    const { data } = props ?? {};

    return sendChatMessage(data, requestOptions);
  };

  return { mutationFn, ...mutationOptions };
};

export type SendChatMessageMutationResult = NonNullable<
  Awaited<ReturnType<typeof sendChatMessage>>
>;
export type SendChatMessageMutationBody = BodyType<ChatMessageBody>;
export type SendChatMessageMutationError = ErrorType<unknown>;

